/**
 * @fileoverview Drawer constants.
 * @module module/Drawer/constants
 */

import { TRANSITION_COLORS } from '../shared/styleFragments.js';
import { defineParts } from '../shared/definePart.js';

export const CLS = Object.freeze({
    ROOT:     'drawer',
    BACKDROP: 'drawer-backdrop',
    PANEL:    'drawer-panel',
    HEADER:   'drawer-header',
    BODY:     'drawer-body',
    FOOTER:   'drawer-footer',
    TITLE:    'drawer-title',
    CLOSE:    'drawer-close',
    OPEN:     'is-open',
});

export const DEFAULTS = Object.freeze({
    position: 'right',   // left | right | top | bottom
    width: '20rem',
    height: '20rem',
    title: '',
    closable: true,
    closeOnBackdrop: true,
});

export const PART = defineParts('Drawer', {
    ROOT        : { class: 'drawer-root', aliases: ['root'] },
    BACKDROP    : { class: 'drawer-backdrop', aliases: ['backdrop', 'overlay'] },
    PANEL       : { class: 'drawer-panel', aliases: ['panel'] },
    HEADER      : { class: 'drawer-header', aliases: ['header'] },
    BODY        : { class: 'drawer-body', aliases: ['body', 'content'] },
    FOOTER      : { class: 'drawer-footer', aliases: ['footer'] },
    TITLE       : { class: 'drawer-title', aliases: ['title'], tag: 'span' },
    CLOSE       : { class: 'drawer-close', aliases: ['close', 'close-btn'], tag: 'button' },
});

PART.ROOT.jit     = 'fixed inset-[0] pointer-events-none {is-open}:pointer-events-auto';
PART.BACKDROP.jit = 'absolute inset-[0] bg-[rgba(0,0,0,0.35)] opacity-0 [transition:opacity_.3s_ease]';
PART.PANEL.jit    = 'absolute bg-[var(--dw-bg)] shadow-[var(--dw-shadow)] flex flex-col [transition:transform_.3s_ease] overflow-hidden';
PART.HEADER.jit   = 'flex items-center justify-between px-[var(--dw-px)] py-[var(--dw-header-py)] [border-bottom:1px_solid_var(--dw-border)]';
PART.BODY.jit     = 'flex-1 px-[var(--dw-px)] py-[var(--dw-py)] overflow-auto';
PART.FOOTER.jit   = 'flex items-center px-[var(--dw-px)] py-[var(--dw-footer-py)] [border-top:1px_solid_var(--dw-border)]';
PART.TITLE.jit    = 'text-[var(--dw-title-size)] font-semibold fg-[var(--dw-title-color)]';
PART.CLOSE.jit    = `cursor-pointer w-[1.5rem] h-[1.5rem] flex items-center justify-center rounded-[var(--dw-radius)] bg-transparent border-0 fg-[var(--dw-close-color)] ${TRANSITION_COLORS} hover:bg-[var(--dw-close-hover-bg)]`;